+        "CREATE TABLE s72a_colors(id INTEGER PRIMARY KEY, name TEXT)",
+        "INSERT INTO s72a_colors VALUES(1,'red'),(2,'blue'),(3,'green')",
+        "CREATE TABLE s72a_sizes(id INTEGER PRIMARY KEY, label TEXT)",
